body {
  font-family: 'Inter var', sans-serif; /* Example variable font for performance */
  font-size: 1.125rem;
  line-height: 1.6;
  color: #333;
}

.main-content {
  max-width: 70ch; /* Optimal line length for readability */
  margin-left: auto;
  margin-right: auto;
  padding: 1.5rem;
  box-sizing: border-box;
  text-rendering: optimizeLegibility; /* Improves kerning & ligatures */
  -webkit-font-smoothing: antialiased; /* Ensure smooth text rendering */
  -moz-osx-font-smoothing: grayscale;
}

@font-face {
  font-family: 'Inter var';
  src: url('/fonts/Inter-roman.var.woff2') format('woff2');
  font-weight: 100 900;
  font-display: swap; /* Prioritize content, then load font */
}
